+@MainActor
+private final class AppControllerTextPasteDeliverer: TextPasteDelivering {
+    var result: PasteDeliveryResult = .pasted
+    var snapshot: PasteSessionSnapshot?
+    private(set) var deliveredTexts: [String] = []
+
+    func deliver(_ text: String, callbacks: PasteLifecycleCallbacks) async -> PasteDeliveryResult {
+        deliveredTexts.append(text)
+        callbacks.onPasteStart()
+        if let snapshot {
+            callbacks.onPasteSession(snapshot)
+        }
+        callbacks.onPasteEnd(result)
+        return result
     }
 }

